css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #0a0014; color: white; overflow-x: hidden; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; position: relative; z-index: 2; }
.brand { font-size: 20px; font-weight: 800; letter-spacing: 0.05em; }
.nav-links { display: flex; gap: 32px; }
.nav-links a { color: rgba(255,255,255,0.65); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-btn { background: linear-gradient(135deg, #a855f7, #ec4899); border: none; color: white; padding: 11px 26px; border-radius: 999px; font-size: 13.5px; font-weight: 700; cursor: pointer; }
.hero { position: relative; padding: 80px 60px 100px; text-align: center; overflow: hidden; }
.hero-bg { position: absolute; inset: 0; background: radial-gradient(circle at 30% 20%, rgba(168,85,247,0.35), transparent 50%), radial-gradient(circle at 70% 80%, rgba(236,72,153,0.35), transparent 50%); }
.hero-content { position: relative; }
.badge { display: inline-block; background: rgba(236,72,153,0.15); color: #f472b6; font-size: 12.5px; font-weight: 700; letter-spacing: 0.1em; padding: 6px 18px; border-radius: 999px; margin-bottom: 24px; }
.hero-content h1 { font-size: 90px; font-weight: 900; line-height: 1; letter-spacing: 0.05em; background: linear-gradient(135deg, #c084fc, #f472b6); -webkit-background-clip: text; background-clip: text; color: transparent; margin-bottom: 22px; }
.hero-content p { color: rgba(255,255,255,0.55); font-size: 16px; margin-bottom: 32px; }
.hero-actions { display: flex; gap: 14px; justify-content: center; flex-wrap: wrap; }
.btn-primary { background: linear-gradient(135deg, #a855f7, #ec4899); border: none; color: white; padding: 15px 30px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; box-shadow: 0 12px 30px rgba(168,85,247,0.3); }
.btn-secondary { background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.18); color: white; padding: 15px 30px; border-radius: 999px; font-size: 14px; font-weight: 700; cursor: pointer; }
.tour, .music, .newsletter { padding: 60px; }
.tour h2, .music h2, .newsletter h2 { font-size: 32px; font-weight: 800; text-align: center; margin-bottom: 40px; }
.tour-list { display: flex; flex-direction: column; gap: 12px; max-width: 700px; margin: 0 auto; }
.tour-item { display: flex; align-items: center; gap: 20px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 16px; padding: 16px 20px; }
.tour-date { display: flex; flex-direction: column; align-items: center; background: rgba(168,85,247,0.12); border-radius: 12px; padding: 8px 14px; flex-shrink: 0; }
.tour-date .day { font-size: 20px; font-weight: 800; color: #c084fc; }
.tour-date .month { font-size: 11px; color: rgba(255,255,255,0.5); font-weight: 700; text-transform: uppercase; }
.tour-info { flex: 1; }
.tour-info h3 { font-size: 16px; font-weight: 700; }
.tour-info span { font-size: 12.5px; color: rgba(255,255,255,0.4); }
.btn-small { background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.15); color: white; padding: 10px 18px; border-radius: 999px; font-size: 12.5px; font-weight: 700; cursor: pointer; }
.track-list { display: flex; flex-direction: column; gap: 10px; max-width: 700px; margin: 0 auto; }
.track { display: flex; align-items: center; gap: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 14px; padding: 14px 18px; cursor: pointer; transition: 0.15s; }
.track:hover, .track.playing { background: rgba(168,85,247,0.1); border-color: rgba(168,85,247,0.3); }
.play { width: 32px; height: 32px; border-radius: 50%; background: rgba(255,255,255,0.08); display: flex; align-items: center; justify-content: center; font-size: 11px; flex-shrink: 0; }
.track.playing .play { background: linear-gradient(135deg, #a855f7, #ec4899); }
.track-art { font-size: 24px; }
.track-info { flex: 1; }
.track-info h3 { font-size: 14.5px; font-weight: 700; }
.track-info span { font-size: 12px; color: rgba(255,255,255,0.4); }
.duration { font-size: 12.5px; color: rgba(255,255,255,0.4); font-weight: 600; }
.newsletter { text-align: center; background: linear-gradient(135deg, rgba(168,85,247,0.1), rgba(236,72,153,0.1)); }
.newsletter p { color: rgba(255,255,255,0.5); font-size: 14px; margin: -24px 0 28px; }
.form-row { display: flex; gap: 12px; max-width: 420px; margin: 0 auto; }
.form-row input { flex: 1; padding: 14px 18px; border-radius: 999px; border: 1px solid rgba(255,255,255,0.15); background: rgba(255,255,255,0.04); color: white; font-size: 14px; outline: none; }
.form-row input::placeholder { color: rgba(255,255,255,0.35); }
@media (max-width: 900px) { .hero, .tour, .music, .newsletter { padding: 50px 24px; } .hero-content h1 { font-size: 52px; } }

