function playTrack(el, name) {
  document.querySelectorAll('.track').forEach(t => { t.classList.remove('playing'); t.querySelector('.play').textContent = '▶'; });
  el.classList.add('playing');
  el.querySelector('.play').textContent = '❚❚';
}

document.querySelector('.newsletter .form-row button').addEventListener('click', () => {
  const input = document.querySelector('.newsletter input');
  if (input.value.includes('@')) {
    alert('Bültene katıldın!');
    input.value = '';
  } else {
    alert('Geçerli bir e-posta girin.');
  }
});
